  // Filters
  const [filterName, setFilterName] = useState('');
  const [filterMonth, setFilterMonth] = useState(''); // Format "01", "02", etc.
  const [filterDate, setFilterDate] = useState(''); // Specific date YYYY-MM-DD

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    // Get ALL history for admin view
    const data = await api.getAllHistory();
    setHistory(data);
    setLoading(false);
  };

  const handleSync = async () => {
    setSyncing(true);
    const result = await api.syncFromCloud();
    if (result.success) {
      alert(`Berjaya menyegerakkan ${result.count} rekod dari Google Sheet.`);
      loadData();
