                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50">Nama Staf & Emel</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50">Jawatan</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50 text-center">Status</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50 text-center">Masuk</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50 text-center">Keluar</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50">Catatan</th>
                            <th className="px-4 py-3 text-[10px] font-bold text-gray-500 uppercase tracking-widest bg-gray-50/50 text-center">Fail</th>
