                                            <p className="text-xs font-bold text-gray-800">{record.name}</p>
                                            <p className="text-[10px] text-gray-400">{record.email}</p>
                                        </div>
                                    </td>
                                    <td className="px-4 py-3">
                                         {/* Assuming position isn't in record, we use a placeholder or derived if available in full user list */}
                                         <span className="text-[10px] font-medium text-gray-500 uppercase">STAF</span>
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                         <span className={`inline-block text-[9px] font-bold px-2 py-0.5 rounded uppercase border ${
                                                record.status === 'BEKERJA' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' :
                                                record.status === 'CUTI' ? 'bg-pink-50 text-pink-600 border-pink-100' :
                                                record.status === 'URUSAN LUAR' ? 'bg-blue-50 text-blue-600 border-blue-100' :
                                                'bg-gray-50 text-gray-500 border-gray-100'
                                            }`}>
                                                {record.status}
                                            </span>
                                            {record.status === 'CUTI' && <span className="block text-[9px] text-gray-400 mt-1">{record.leaveType}</span>}
                                            {record.status === 'URUSAN LUAR' && <span className="block text-[9px] text-gray-400 mt-1">{record.outstationType?.replace('_', ' ')}</span>}
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                        <span className={`text-xs font-bold ${record.timeIn ? 'text-gray-700' : 'text-gray-300 italic'}`}>
                                            {record.timeIn || '--:--'}
                                        </span>
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                        <span className={`text-xs font-bold ${record.timeOut ? 'text-gray-700' : 'text-gray-300 italic'}`}>
                                            {record.timeOut || '--:--'}
                                        </span>
                                    </td>
                                    <td className="px-4 py-3">
                                        <p className="text-[10px] text-gray-600 leading-tight max-w-[150px] truncate" title={record.reason || record.location}>
                                            {record.reason || record.location || '-'}
                                        </p>
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                        {record.document ? (
                                            <a href="#" className="text-indigo-600 hover:text-indigo-800"><ExternalLink size={14} /></a>
                                        ) : (
                                            <span className="text-gray-200">-</span>
                                        )}
                                    </td>
                                </tr>
                            ))
                        ) : (
                            <tr><td colSpan={8} className="px-6 py-12 text-center text-sm text-gray-400">Tiada rekod dijumpai.</td></tr>
                        )}
                    </tbody>
                </table>
