export const api = {
  // NEW: Sync Data from Google Sheet CSV
  syncFromCloud: async (): Promise<{ success: boolean; count: number }> => {
      try {
          console.log("Fetching from:", GOOGLE_SHEET_CSV_URL);
          const response = await fetch(GOOGLE_SHEET_CSV_URL);
          if (!response.ok) throw new Error("Gagal menyambung ke Sheet");

          const text = await response.text();
          // Split CSV properly (handling quotes roughly)
          const rows = text.split('\n').map(row => row.split(',')); 

          // Assumption based on requested headers:
          // 0:Timestamp, 1:Email, 2:Name, 3:Status, 4:TimeIn, 5:TimeOut, 6:Reason, 7:Lat, 8:Lon, 9:Doc

          const newRecords: AttendanceRecord[] = [];

          // Start from i=1 to skip Header row
          for (let i = 1; i < rows.length; i++) {
              const col = rows[i];
              if (col.length < 3) continue; // Skip empty rows

              const timestamp = col[0]?.replace(/"/g, '').trim(); 
              const email = col[1]?.replace(/"/g, '').trim();
              const name = col[2]?.replace(/"/g, '').trim();
              const statusRaw = col[3]?.replace(/"/g, '').trim().toUpperCase();

              let status = AttendanceStatus.WORKING;
              if (statusRaw.includes('CUTI')) status = AttendanceStatus.LEAVE;
              if (statusRaw.includes('LUAR')) status = AttendanceStatus.OUTSTATION;

              // Parse Date
              let date = new Date().toISOString().split('T')[0];
              if (timestamp) {
                  // Try to parse format DD/MM/YYYY or MM/DD/YYYY
                  const datePart = timestamp.split(' ')[0];
                  if (datePart.includes('/')) {
                     const parts = datePart.split('/');
                     // Assume DD/MM/YYYY
                     if (parts.length === 3) {
                        date = `${parts[2]}-${parts[1]}-${parts[0]}`;
                     }
                  }
              }

              const record: AttendanceRecord = {
                  id: `cloud-${i}-${date}`, // Create unique ID based on row index
                  email: email,
                  name: name,
                  date: date,
                  timeIn: col[4]?.replace(/"/g, '').trim() || "00:00",
                  timeOut: col[5]?.replace(/"/g, '').trim(),
                  status: status,
                  reason: col[6]?.replace(/"/g, '').trim(),
                  location: (col[7] && col[8]) ? `${col[7]}, ${col[8]}` : undefined,
                  document: col[9]?.replace(/"/g, '').trim(),
                  deviceType: 'Cloud Import'
              };

              newRecords.push(record);
          }

          if (newRecords.length > 0) {
              const currentHistory = getHistoryData();
              // Remove old cloud records to prevent duplicates, keep local records
              const localOnly = currentHistory.filter(h => !h.id.startsWith('cloud-'));
              const merged = [...newRecords, ...localOnly];

              // Sort by date desc
              merged.sort((a,b) => b.date.localeCompare(a.date));

              saveHistoryData(merged);
              return { success: true, count: newRecords.length };
          }

          return { success: true, count: 0 };

      } catch (error) {
