}

export const ClockIn: React.FC<ClockInProps> = ({ user }) => {
  const navigate = useNavigate();
  const [status, setStatus] = useState<AttendanceStatus>(AttendanceStatus.WORKING);
  const [gpsData, setGpsData] = useState<{ lat: number; lon: number; dist: number } | null>(null);
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [loading, setLoading] = useState(false);
  const [isLate, setIsLate] = useState(false);
  const [reason, setReason] = useState('');

  const [currentRecordId, setCurrentRecordId] = useState<string | null>(null);
  const [showClockOutModal, setShowClockOutModal] = useState(false);

  const [outstationType, setOutstationType] = useState<'RASMI' | 'TIDAK_RASMI'>('RASMI');
  const [outstationCategory, setOutstationCategory] = useState('');
  const [outstationTitle, setOutstationTitle] = useState('');
  const [outstationLocation, setOutstationLocation] = useState('');
  const [leaveType, setLeaveType] = useState('');
  const [fileName, setFileName] = useState('Tiada fail dipilih');
  const [documentData, setDocumentData] = useState<string | undefined>(undefined);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);

  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isClockedOut, setIsClockedOut] = useState(false);
  const [submissionTime, setSubmissionTime] = useState('');
  const [clockOutTime, setClockOutTime] = useState('');
  const [workDuration, setWorkDuration] = useState(0);
  const [currentTimeStr, setCurrentTimeStr] = useState('');
  const [currentDateStr, setCurrentDateStr] = useState('');

  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const getDeviceType = () => {
    const width = window.innerWidth;
    if (width < 768) return 'Mobile';
    if (width < 1024) return 'Tablet';
    return 'PC';
  };

  const parseTimeStr = (timeStr: string) => {
    const [time, modifier] = timeStr.split(' ');
    let [hours, minutes] = time.split(':');
    let h = parseInt(hours, 10);
    if (h === 12 && modifier === 'AM') h = 0;
    if (h !== 12 && modifier === 'PM') h += 12;
    const d = new Date();
    d.setHours(h, parseInt(minutes, 10), 0, 0);
    return d;
  };

  useEffect(() => {
    api.getSettings().then((data) => {
        setSettings(data);
        checkLateStatus(data);
        if (data.outstationTypes.length > 0) setOutstationCategory(data.outstationTypes[0]);
        if (data.leaveTypes.length > 0) setLeaveType(data.leaveTypes[0]);
    });

    const checkActiveSession = async () => {
        const history = await api.getHistory(user.email);
        const today = new Date().toISOString().split('T')[0];
        const todayRecord = history.find(h => h.date === today && h.status === AttendanceStatus.WORKING);

        if (todayRecord) {
            setCurrentRecordId(todayRecord.id);
            setStatus(AttendanceStatus.WORKING);
            setSubmissionTime(todayRecord.timeIn);

            if (todayRecord.timeOut) {
                setIsSubmitted(true);
                setIsClockedOut(true);
                setClockOutTime(todayRecord.timeOut);
            } else {
                setIsSubmitted(true);
                setIsClockedOut(false);
                try {
                    const start = parseTimeStr(todayRecord.timeIn);
                    const now = new Date();
                    const diff = Math.floor((now.getTime() - start.getTime()) / 1000);
                    setWorkDuration(diff > 0 ? diff : 0);
                } catch (e) {
                    console.error("Error parsing time", e);
                }
            }
        }
    };
    checkActiveSession();
  }, []);

  useEffect(() => {
      const updateClock = () => {
        const d = new Date();
        setCurrentTimeStr(d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true }));
        const day = d.toLocaleDateString('ms-MY', { weekday: 'long' });
        const date = d.toLocaleDateString('ms-MY', { day: 'numeric', month: 'long', year: 'numeric' });
        setCurrentDateStr(`${day.toUpperCase()}, ${date}`);
        if (settings) {
            checkLateStatus(settings);
        }
    };
    updateClock();
    const clockInterval = setInterval(updateClock, 1000);
    return () => clearInterval(clockInterval);
  }, [settings, user.role, user.position]);

  useEffect(() => {
    if (isSubmitted && !isClockedOut && status === AttendanceStatus.WORKING) {
        timerRef.current = setInterval(() => {
            setWorkDuration(prev => prev + 1);
        }, 1000);
    } else if ((isClockedOut || status !== AttendanceStatus.WORKING) && timerRef.current) {
        clearInterval(timerRef.current);
    }
    return () => {
        if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isSubmitted, isClockedOut, status]);

  const checkLateStatus = (currentSettings: SystemSettings) => {
      const now = new Date();
      const currentMinutes = now.getHours() * 60 + now.getMinutes();
      const userRole = user.role || user.position || 'GURU'; 
      const targetTimeStr = currentSettings.roleClockInTimes[userRole] || 
                            currentSettings.roleClockInTimes['GURU'] || 
                            currentSettings.clockInTime;
      if (!targetTimeStr) return;
      const [inHour, inMin] = targetTimeStr.split(':').map(Number);
      const limitIn = inHour * 60 + inMin;
      setIsLate(currentMinutes > limitIn);
  };

  const formatDuration = (totalSeconds: number) => {
    const hrs = Math.floor(totalSeconds / 3600);
    const mins = Math.floor((totalSeconds % 3600) / 60);
    const secs = totalSeconds % 60;
    return `${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371e3;
    const φ1 = lat1 * Math.PI / 180;
    const φ2 = lat2 * Math.PI / 180;
    const Δφ = (lat2-lat1) * Math.PI / 180;
    const Δλ = (lon2-lon1) * Math.PI / 180;
    const a = Math.sin(Δφ/2) * Math.sin(Δφ/2) + Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ/2) * Math.sin(Δλ/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return R * c;
  };

  useEffect(() => {
    if (status === AttendanceStatus.WORKING && !isSubmitted) {
      if (navigator.geolocation) {
        navigator.geolocation.watchPosition(
          (pos) => {
            if (settings) {
              const dist = calculateDistance(pos.coords.latitude, pos.coords.longitude, settings.targetLat, settings.targetLon);
              setGpsData({ lat: pos.coords.latitude, lon: pos.coords.longitude, dist });
            }
          },
          (err) => console.error(err),
          { enableHighAccuracy: true, maximumAge: 10000, timeout: 5000 }
        );
      }
    }
  }, [status, settings, isSubmitted]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFileName(file.name);
      const reader = new FileReader();
      reader.onloadend = () => {
        setDocumentData(reader.result as string);
      };
      reader.readAsDataURL(file);
    } else {
      setFileName('Tiada fail dipilih');
      setDocumentData(undefined);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (status === AttendanceStatus.WORKING && settings) {
        if (!gpsData || gpsData.dist > settings.radiusMeter) {
             alert("Anda berada di luar kawasan sekolah!");
             return;
        }
    }

    setLoading(true);
    try {
        const now = new Date();
        const timeString = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: false });

        const res = await api.clockIn({
            email: user.email,
            status,
            lat: gpsData?.lat,
            lon: gpsData?.lon,
            reason: (status === AttendanceStatus.WORKING && isLate) ? reason : undefined,
            outstationType: status === AttendanceStatus.OUTSTATION ? outstationType : undefined,
            outstationCategory: outstationCategory,
            leaveType: leaveType,
            startDate: startDate,
            endDate: endDate,
            document: documentData,
            deviceType: getDeviceType() 
        });

        if (res.success) {
            if (res.record) setCurrentRecordId(res.record.id);
            setSubmissionTime(timeString);
            setIsSubmitted(true);
            window.scrollTo(0, 0);
        }
    } catch (e) {
        alert("Ralat sistem.");
    } finally {
        setLoading(false);
    }
  };

  const handleClockOut = async () => {
    setShowClockOutModal(false);
    setLoading(true);
    try {
        const now = new Date();
        const outTimeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
        if (currentRecordId) {
            await api.updateAttendanceRecord(currentRecordId, { timeOut: outTimeStr });
        }
        setTimeout(() => {
            setClockOutTime(outTimeStr);
            setIsClockedOut(true);
            setLoading(false);
            window.scrollTo(0, 0);
        }, 800);
    } catch (e) {
        alert("Gagal melakukan Clock Out.");
        setLoading(false);
    }
  };

  const StatusButton = ({ type, label, icon: Icon }: any) => (
    <button 
        type="button"
        disabled={isSubmitted}
        onClick={() => setStatus(type)}
        className={`relative p-4 rounded-[20px] flex flex-col items-center justify-center gap-2 transition-all h-28 w-full border
            ${status === type 
                ? 'bg-[#0f172a] text-white shadow-xl scale-[1.02] border-[#0f172a]' 
                : 'bg-white text-slate-900 border-slate-200 shadow-sm hover:bg-slate-50'
            }`}
    >
        <div className={`p-2 rounded-lg ${status === type ? 'bg-white/10' : 'bg-slate-100'}`}>
            <Icon size={24} strokeWidth={2.5} />
        </div>
        <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen px-6 py-8 pb-32 max-w-lg mx-auto bg-[#f8f9fc]">
      <div className="text-center mb-10 pt-4 animate-fade-in">
         <h1 className="text-6xl font-semibold tracking-tighter mb-2 text-[#0f172a] tabular-nums">
            {currentTimeStr}
         </h1>
         <div className="flex flex-col items-center gap-1">
             <p className="text-[12px] text-indigo-600 font-bold uppercase tracking-[0.15em] bg-indigo-50 px-4 py-1.5 rounded-full shadow-sm">
                {currentDateStr}
             </p>
         </div>
      </div>

      {isSubmitted ? (
        <div className="animate-slide-up">
            {/* ... Existing submitted view logic ... */}
             <div className="bg-[#0f172a] rounded-[45px] p-8 text-center text-white shadow-xl mb-8 relative overflow-hidden">
                    <div className="flex flex-col items-center">
                        <div className="bg-white/10 p-4 rounded-full mb-4">
                            <Check size={32} className="text-[#10b981]" strokeWidth={3} />
                        </div>
                        <h3 className="text-xl font-bold mb-1 tracking-tight">Rekod Berjaya!</h3>
                        <p className="text-xs text-gray-400 font-medium uppercase tracking-widest">Sistem telah mengemas kini status anda.</p>
                    </div>
            </div>
            {status === AttendanceStatus.WORKING ? (
                !isClockedOut ? (
                    <button 
                        onClick={() => setShowClockOutModal(true)}
                        className="w-full bg-red-600 text-white font-bold py-6 rounded-[30px] shadow-lg"
                    >
                        CLOCK OUT
                    </button>
                ) : <div className="text-center font-bold text-gray-400">Sesi Tamat</div>
            ) : (
                <button onClick={() => navigate('/')} className="w-full bg-indigo-600 text-white font-bold py-6 rounded-[30px]">KEMBALI KE UTAMA</button>
            )}
             {/* ... Simple view ... */}
             {showClockOutModal && (
                 <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
                     <div className="bg-white p-6 rounded-2xl w-full max-w-xs text-center">
                         <h3 className="font-bold text-lg mb-4">Clock Out Sekarang?</h3>
                         <button onClick={handleClockOut} className="w-full bg-red-600 text-white py-3 rounded-xl font-bold mb-2">YA</button>
                         <button onClick={() => setShowClockOutModal(false)} className="w-full bg-gray-100 text-gray-600 py-3 rounded-xl font-bold">BATAL</button>
                     </div>
                 </div>
             )}
        </div>
      ) : (
        <div className="animate-fade-in">
          <form onSubmit={handleSubmit}>
            <div className="grid grid-cols-3 gap-4 mb-8">
                <StatusButton type={AttendanceStatus.WORKING} label="Bekerja" icon={Briefcase} />
                <StatusButton type={AttendanceStatus.OUTSTATION} label="Luar" icon={Plane} />
                <StatusButton type={AttendanceStatus.LEAVE} label="Cuti" icon={CalendarX} />
            </div>

            {status === AttendanceStatus.WORKING && (
                <div className="space-y-4 mb-8">
                    {/* Location Status Logic */}
                    <div className="bg-white rounded-[32px] p-8 shadow-[0_10px_30px_rgba(0,0,0,0.02)] border border-gray-50 transition-all">
