                            </div>
                            {gpsData && settings ? (
                                <div className={`px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-wider transition-colors ${gpsData.dist <= settings.radiusMeter ? 'bg-[#dcfce7] text-[#166534]' : 'bg-[#fee2e2] text-[#991b1b]'}`}>
                                    {gpsData.dist <= settings.radiusMeter ? 'Dalam Radius' : 'Luar Radius'}
                                </div>
                            ) : (
                                <div className="px-4 py-2 rounded-full bg-gray-50 text-gray-300 text-[10px] font-bold uppercase tracking-wider animate-pulse">
                                    Mengesan...
                                </div>
                            )}
                        </div>

                        <div className="flex items-end justify-between mb-4">
                            <div className="flex items-baseline gap-2">
                                <span className="text-5xl font-bold text-[#0f172a] tabular-nums">
                                    {gpsData ? Math.round(gpsData.dist) : '0'}
                                </span>
                                <span className="text-sm font-bold text-gray-300 uppercase tracking-widest">Meter</span>
                            </div>
                        </div>
                    </div>

                    {isLate && (
                        <textarea 
                            value={reason} onChange={(e) => setReason(e.target.value)}
                            placeholder="Sebab Lewat..." 
                            className="w-full p-4 bg-red-50 rounded-2xl text-sm border border-red-100"
                            required
                        />
                    )}
                </div>
            )}

            {/* Outstation Form */}
            {status === AttendanceStatus.OUTSTATION && (
                <div className="bg-white rounded-[32px] p-8 shadow-sm border border-gray-50 mb-8 space-y-4">
                     <select value={outstationCategory} onChange={(e) => setOutstationCategory(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold">
                        {(outstationType === 'RASMI' ? settings?.outstationTypes : settings?.outstationUnofficialTypes)?.map((t, i) => <option key={i} value={t}>{t}</option>)}
                     </select>
                     <input type="text" placeholder="Tajuk Urusan" value={outstationTitle} onChange={(e) => setOutstationTitle(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold" />
                     <input type="text" placeholder="Lokasi" value={outstationLocation} onChange={(e) => setOutstationLocation(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold" />

