                     </a>
                </div>
            )}

            {/* Leave Form */}
            {status === AttendanceStatus.LEAVE && (
                <div className="bg-white rounded-[32px] p-8 shadow-sm border border-gray-50 mb-8 space-y-4">
                     <select value={leaveType} onChange={(e) => setLeaveType(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold">
                        {settings?.leaveTypes.map((t, i) => <option key={i} value={t}>{t}</option>)}
                     </select>
                     <div className="flex gap-2">
                        <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold" />
                        <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full bg-gray-50 p-4 rounded-2xl text-sm font-bold" />
                     </div>

                     {/* DRIVE LINK BUTTON */}
                     <a href={GOOGLE_DRIVE_URL} target="_blank" className="block w-full bg-pink-50 text-pink-600 font-bold py-3 rounded-2xl text-center text-xs uppercase tracking-wider border border-pink-100 hover:bg-pink-100">
                        <Upload size={14} className="inline mr-2"/> Muat Naik Sijil Ke Drive
                     </a>
                </div>
            )}

            <button 
                type="submit" 
                disabled={loading || (status === AttendanceStatus.WORKING && (!gpsData || (settings && gpsData.dist > settings.radiusMeter)))}
                className="w-full bg-[#0f172a] hover:bg-[#1e293b] disabled:opacity-30 disabled:grayscale text-white font-bold py-6 rounded-[30px] shadow-2xl shadow-indigo-100 transition-all transform active:scale-[0.98] text-sm tracking-[0.2em] uppercase"
            >
                 {loading ? 'Memproses...' : (status === AttendanceStatus.WORKING ? 'Clock In' : 'Rekod Sekarang')}
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

