// HELPER: SEND DATA TO GOOGLE SHEET VIA APPS SCRIPT
const postToCloud = async (action: string, payload: any) => {
    if (GOOGLE_SCRIPT_URL.includes("PASTE_YOUR")) {
        console.warn("URL Google Apps Script belum ditetapkan. Data hanya disimpan secara lokal.");
        return;
    }

    try {
        // 'no-cors' mode is critical for simple fire-and-forget logging to GAS
        await fetch(GOOGLE_SCRIPT_URL, {
            method: 'POST',
            mode: 'no-cors', 
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                action,
                ...payload
            })
        });
        console.log(`Cloud Sync Sent: ${action}`);
    } catch (e) {
        console.error("Cloud Sync Failed:", e);
    }
};

