        history[index] = { ...history[index], ...updates };
        saveHistoryData(history);

        // --- CLOCK OUT KE CLOUD SHEET ---
        // Jika ada timeOut dalam updates, kita anggap ini proses clock-out
        if (updates.timeOut) {
             const record = history[index];
             postToCloud('CLOCK_OUT', {
                 email: record.email,
                 timeOut: updates.timeOut
             });
