  updateAttendanceRecord: async (id: string, updates: Partial<AttendanceRecord>): Promise<boolean> => {
    await delay(300);
    const history = getHistoryData();
    const index = history.findIndex(r => r.id === id);
    if (index !== -1) {
        history[index] = { ...history[index], ...updates };
        saveHistoryData(history);
        // Note: Updating existing row in Sheet via GAS requires RowID tracking which is complex.
        // For simplicity, we assume ClockOut creates a new row or isn't strictly synced via this simple POST.
        // A robust system would need Row ID from Sheet returned during Clock In.
        return true;
    }
    return false;
  },

  getStaff: async (): Promise<StaffMember[]> => {
