            ],
            leave: leave.map(s => ({ name: s.name, photo: s.photo, detail: s.leaveType || 'CUTI BERREKOD' })), 
            pending: pending.map(s => ({ name: s.name, photo: s.photo, detail: 'Tiada Rekod' }))
