                         <input type="text" placeholder="Lokasi" value={outstationLocation} onChange={(e) => setOutstationLocation(e.target.value)} className="w-full bg-slate-50 px-5 py-4 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-100 placeholder:text-slate-300" />

                         {/* REMOVED: Google Drive Link Button for Outstation */}
                    </div>
                )}

                {/* 3. LEAVE FORM */}
                {status === AttendanceStatus.LEAVE && (
                    <div className="bg-white rounded-[32px] p-6 shadow-xl shadow-rose-100/50 border border-white mb-6 space-y-4">
                         <div>
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2 mb-1 block">Jenis Cuti</label>
                            <select value={leaveType} onChange={(e) => setLeaveType(e.target.value)} className="w-full bg-slate-50 px-5 py-4 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-rose-100">
                                {settings?.leaveTypes.map((t, i) => <option key={i} value={t}>{t}</option>)}
                            </select>
                         </div>

                         <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2 mb-1 block">Mula</label>
                                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-slate-50 px-4 py-4 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-rose-100" />
                            </div>
                            <div>
                                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2 mb-1 block">Tamat</label>
                                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full bg-slate-50 px-4 py-4 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-rose-100" />
                            </div>
                         </div>

                         {/* UPDATED: Local File Upload for Leave */}
                         <div className="mt-2">
                             <label className="flex flex-col items-center justify-center w-full h-28 border-2 border-dashed border-rose-200 rounded-[24px] cursor-pointer bg-rose-50 hover:bg-rose-100 transition-colors group">
                                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                                    <div className="bg-white p-2 rounded-full shadow-sm mb-2 group-hover:scale-110 transition-transform">
                                        <Upload size={20} className="text-rose-500" />
                                    </div>
                                    <p className="text-[10px] text-rose-500 font-bold uppercase tracking-wide text-center px-4 leading-tight">
                                        {fileName !== 'Tiada fail dipilih' ? (
                                            <span className="text-rose-700 break-all line-clamp-2">{fileName}</span>
                                        ) : (
                                            'Muat Naik Dokumen/Sijil'
                                        )}
                                    </p>
                                </div>
                                <input type="file" className="hidden" onChange={handleFileChange} accept="image/*,application/pdf" />
                             </label>
                         </div>
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={loading || (status === AttendanceStatus.WORKING && (!gpsData || (settings && gpsData.dist > settings.radiusMeter)))}
                    className="w-full bg-[#0f172a] hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed text-white font-black py-6 rounded-[30px] shadow-2xl shadow-slate-300 transition-all transform active:scale-[0.98] text-xs tracking-[0.2em] uppercase flex items-center justify-center gap-3"
                >
                     {loading ? (
                         <span className="flex items-center gap-2">
                             <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                             Memproses...
                         </span>
                     ) : (
                         status === AttendanceStatus.WORKING ? 'PUNCH IN SEKARANG' : 'HANTAR REKOD'
                     )}
                </button>
              </form>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { api } from '../services/mockApi';
import { AttendanceRecord, User } from '../types';
import { Search, Printer, ArrowLeft, Calendar, User as UserIcon, Filter, ExternalLink, FileText, MapPin } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const ReportSheet: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const navigate = useNavigate();
  const [history, setHistory] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);

  // Filters
  const [filterName, setFilterName] = useState('');
  const [filterMonth, setFilterMonth] = useState(''); 
  const [filterDate, setFilterDate] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await api.getAllHistory();
    setHistory(data);
    setLoading(false);
  };

  const filteredHistory = history.filter(record => {
    const matchName = record.name.toLowerCase().includes(filterName.toLowerCase());
    const recordMonth = record.date.split('-')[1]; 
    const matchMonth = filterMonth ? recordMonth === filterMonth : true;
    const matchDate = filterDate ? record.date === filterDate : true;
    return matchName && matchMonth && matchDate;
  });

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Sila benarkan 'Pop-up' untuk mencetak laporan.");
        return;
    }

    const rowsHtml = filteredHistory.map((rec, index) => {
        const displayStatus = rec.status;
        const timeInDisplay = rec.status === 'BEKERJA' ? rec.timeIn : '--';
        const timeOutDisplay = rec.status === 'BEKERJA' ? (rec.timeOut || '--') : '--';
        const location = rec.location ? rec.location : '-';
        const notes = rec.reason ? rec.reason : '-';

        return `
            <tr>
                <td style="text-align:center;">${index + 1}</td>
                <td style="text-align:center;">${rec.date}</td>
                <td>${rec.name}</td>
                <td>${rec.email}</td>
                <td style="text-align:center;">${displayStatus}</td>
                <td style="text-align:center;">${timeInDisplay}</td>
                <td style="text-align:center;">${timeOutDisplay}</td>
                <td>${notes}</td>
                <td style="font-size:8px;">${location}</td>
            </tr>
        `;
    }).join('');

    const htmlContent = `
        <!DOCTYPE html>
        <html>
        <head>
            <title>Laporan Penuh</title>
            <style>
                body { font-family: sans-serif; padding: 20px; font-size: 10px; }
                table { width: 100%; border-collapse: collapse; margin-top: 10px; }
                th, td { border: 1px solid #ddd; padding: 6px; text-align: left; }
                th { background-color: #f2f2f2; font-weight: bold; text-transform: uppercase; }
                h1 { color: #1e40af; }
            </style>
        </head>
        <body>
            <h1>LAPORAN KEHADIRAN SK PEKAN KIMANIS</h1>
            <p>Tarikh Cetakan: ${new Date().toLocaleDateString()}</p>
            <table>
                <thead>
                    <tr>
                        <th width="3%">No</th>
                        <th width="10%">Tarikh</th>
                        <th width="20%">Nama</th>
                        <th width="15%">Emel</th>
                        <th width="10%">Status</th>
                        <th width="8%">Masuk</th>
                        <th width="8%">Keluar</th>
                        <th width="15%">Catatan</th>
                        <th width="11%">Lokasi (GPS)</th>
                    </tr>
                </thead>
                <tbody>
                    ${rowsHtml}
                </tbody>
            </table>
        </body>
        </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">

      {/* HEADER */}
      <div className="bg-white px-6 py-6 shadow-sm border-b border-gray-100 sticky top-0 z-20">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex items-center gap-4">
                <button onClick={() => navigate('/')} className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500">
                    <ArrowLeft size={24} />
                </button>
                <div>
                    <h1 className="text-xl font-bold text-gray-900">Jadual Induk Kehadiran</h1>
                    <p className="text-xs text-gray-400">Sinkronasi Data Staf & Kehadiran</p>
                </div>
            </div>

            <div className="flex gap-3">
                <button 
                    onClick={handlePrint}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95 text-xs uppercase tracking-wider"
                >
                    <Printer size={16} />
                    CETAK
                </button>
            </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-8">

        {/* FILTERS */}
        <div className="bg-white rounded-2xl p-6 shadow-sm mb-6 border border-gray-100 flex flex-col md:flex-row gap-4 items-center">
             <div className="relative flex-1 w-full">
                <UserIcon className="absolute left-3 top-3.5 text-gray-400" size={16} />
                <input 
                    type="text" 
                    placeholder="Cari Nama..." 
                    value={filterName}
                    onChange={(e) => setFilterName(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold text-gray-700 outline-none"
                />
            </div>
            <div className="relative flex-1 w-full">
                <input 
                    type="date" 
                    value={filterDate}
                    onChange={(e) => setFilterDate(e.target.value)}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold text-gray-700 outline-none"
                />
            </div>
        </div>

        {/* DATA TABLE */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
