                                <div 
                                    className={`h-full rounded-full transition-all duration-700 ease-out ${
                                        gpsData && settings && gpsData.dist <= settings.radiusMeter 
                                        ? 'bg-emerald-500' : 'bg-rose-500'
                                    }`} 
                                    style={{ 
