  updateProfile: async (updatedUser: User): Promise<{ success: boolean; user: User }> => {
      await delay(500);
      const users = getUsers();
      const index = users.findIndex(u => u.email === updatedUser.email);
      if (index !== -1) {
          if (!updatedUser.password) updatedUser.password = users[index].password;
          if (updatedUser.email === 'g-65253270@moe-dl.edu.my') updatedUser.isAdmin = 'YES';

          users[index] = updatedUser;
          saveUsers(users);

          // SAVE TO CLOUD SHEET
          postToCloud('UPDATE_STAFF', updatedUser);

          return { success: true, user: updatedUser };
      }
      return { success: false, user: updatedUser };
  },

  deleteUser: async (email: string): Promise<boolean> => {
      await delay(500);
      if (email === 'g-65253270@moe-dl.edu.my') return false;

      const users = getUsers();
      const filtered = users.filter(u => u.email !== email);
      if (filtered.length < users.length) {
          saveUsers(filtered);
          const history = getHistoryData();
          const filteredHistory = history.filter(h => h.email !== email);
          saveHistoryData(filteredHistory);

          // DELETE FROM CLOUD SHEET
          postToCloud('DELETE_STAFF', { email });

          return true;
      }
      return false;
  },

  clockIn: async (data: any): Promise<{ success: boolean; record?: AttendanceRecord }> => {
    await delay(800);
    const history = getHistoryData();
    const now = new Date();

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      email: data.email,
      name: getUsers().find(u => u.email === data.email)?.name || 'Unknown',
      date: now.toISOString().split('T')[0],
      timeIn: now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
      status: data.status,
      outstationType: data.outstationType,
      leaveType: data.leaveType, 
      document: data.document,
      location: data.lat ? `${data.lat.toFixed(4)}, ${data.lon.toFixed(4)}` : undefined,
      reason: data.reason,
      deviceType: data.deviceType
    };

    history.unshift(newRecord);
    saveHistoryData(history);

    // SAVE CLOCK IN TO CLOUD SHEET
    postToCloud('CLOCK_IN', {
        email: newRecord.email,
        name: newRecord.name,
        status: newRecord.status,
        timeIn: newRecord.timeIn,
        timeOut: "",
        reason: newRecord.reason,
        lat: data.lat,
        lon: data.lon,
        document: newRecord.document || ""
    });

    return { success: true, record: newRecord };
  },

  getHistory: async (email: string): Promise<AttendanceRecord[]> => {
    await delay(300);
    const history = getHistoryData();
    return history.filter(h => h.email === email).sort((a,b) => b.date.localeCompare(a.date));
  },

  getAllHistory: async (): Promise<AttendanceRecord[]> => {
    await delay(300);
    const history = getHistoryData();
    return history.sort((a,b) => b.date.localeCompare(a.date));
  },

  updateAttendanceRecord: async (id: string, updates: Partial<AttendanceRecord>): Promise<boolean> => {
    await delay(300);
    const history = getHistoryData();
    const index = history.findIndex(r => r.id === id);
    if (index !== -1) {
        history[index] = { ...history[index], ...updates };
        saveHistoryData(history);
        return true;
    }
    return false;
  },

  getStaff: async (): Promise<StaffMember[]> => {
    await delay(400);
    const users = getUsers();
    const history = getHistoryData();
    const today = new Date().toISOString().split('T')[0];

    const staffList: StaffMember[] = users.map(user => {
        const todayRecord = history.find(h => h.email === user.email && h.date === today);
        return {
            name: user.name,
            email: user.email,
            position: user.position,
            role: user.role || user.position,
            photo: user.photo,
            isAdmin: user.isAdmin,
            status: todayRecord ? todayRecord.status : AttendanceStatus.NONE,
            outstationType: todayRecord?.outstationType,
            leaveType: todayRecord?.leaveType,
            phoneNumber: user.phoneNumber,
            customClockIn: user.customClockIn,
            customClockOut: user.customClockOut
        };
    });

    return staffList;
  },

  adminUpdateUser: async (email: string, updates: Partial<User>): Promise<boolean> => {
      await delay(500);
      const users = getUsers();
      const index = users.findIndex(u => u.email === email);
      if (index !== -1) {
          if (email === 'g-65253270@moe-dl.edu.my') {
              updates.isAdmin = 'YES';
          }
          const updatedUser = { ...users[index], ...updates };
          users[index] = updatedUser;
          saveUsers(users);

          // SAVE TO CLOUD SHEET
          postToCloud('UPDATE_STAFF', updatedUser);

          return true;
      }
      return false;
  },

  getDashboardStats: async (): Promise<{ stats: DashboardStats, lists: any }> => {
    await delay(500);
    const staff = await api.getStaff();
    const working = staff.filter(s => s.status === AttendanceStatus.WORKING);
    const outOfficial = staff.filter(s => s.status === AttendanceStatus.OUTSTATION && (!s.outstationType || s.outstationType === 'RASMI'));
    const outUnofficial = staff.filter(s => s.status === AttendanceStatus.OUTSTATION && s.outstationType === 'TIDAK_RASMI');
    const leave = staff.filter(s => s.status === AttendanceStatus.LEAVE);
    const pending = staff.filter(s => s.status === AttendanceStatus.NONE);

    return {
        stats: { 
            working: working.length, 
            outOfficial: outOfficial.length, 
            outUnofficial: outUnofficial.length, 
            leave: leave.length, 
            pending: pending.length 
        },
        lists: {
            working: working.map(s => ({ name: s.name, photo: s.photo, detail: 'Hadir Bertugas' })),
            out: [
              ...outOfficial.map(s => ({ name: s.name, photo: s.photo, detail: 'URUSAN RASMI' })),
              ...outUnofficial.map(s => ({ name: s.name, photo: s.photo, detail: 'URUSAN TIDAK RASMI' }))
            ],
            leave: leave.map(s => ({ name: s.name, photo: s.photo, detail: s.leaveType || 'CUTI BERREKOD' })), 
            pending: pending.map(s => ({ name: s.name, photo: s.photo, detail: 'Tiada Rekod' }))
        }
    };
  },

  getSettings: async (): Promise<SystemSettings> => {
      await delay(200);
      return safeJSONParse(KEY_SETTINGS, { ...DEFAULT_SETTINGS });
  },

  updateSettings: async (newSettings: SystemSettings): Promise<boolean> => {
      await delay(300);
      localStorage.setItem(KEY_SETTINGS, JSON.stringify(newSettings));
      return true;
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Auth } from './components/Auth';
import { Profile } from './components/Profile';
import { Dashboard } from './components/Dashboard';
import { ClockIn } from './components/ClockIn';
import { History } from './components/History';
import { Directory } from './components/Directory';
import { AdminDashboard } from './components/AdminDashboard';
import { ReportSheet } from './components/ReportSheet';
import { Navigation } from './components/Navigation';
import { User } from './types';
import { api } from './services/mockApi';

// Protected Route Wrapper
interface ProtectedRouteProps {
  children?: React.ReactNode;
  user: User | null;
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children, user }) => {
  if (!user) {
    return <Navigate to="/auth" replace />;
  }
  return <>{children}</>;
};

const AppContent = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    // Check local storage for session
    const storedSession = localStorage.getItem('userSession');
    if (storedSession) {
      try {
        const sessionUser = JSON.parse(storedSession) as User;

        // REFRESH SESSION: Check if user still exists in our local "database"
        const storedUsersStr = localStorage.getItem('skpk_users');
        if (storedUsersStr) {
          const allUsers = JSON.parse(storedUsersStr) as User[];
          const freshUser = allUsers.find(u => u.email === sessionUser.email);

          if (freshUser) {
            // Update session with latest data (in case name/position/admin changed)
            setUser(freshUser);
            localStorage.setItem('userSession', JSON.stringify(freshUser));
          } else {
            // User no longer exists in database (e.g. deleted by admin)
            localStorage.removeItem('userSession');
            setUser(null);
          }
        } else {
          // No users list found in DB, fallback to session data or logout
          setUser(sessionUser);
        }
      } catch (e) {
        console.error("Session corrupted", e);
        localStorage.removeItem('userSession');
      }
    }
    setLoading(false);
  }, []);

  // ---------------------------------------------------------------------------
  // LOGIK NOTIFIKASI LEWAT (LATE NOTIFICATION LOGIC)
  // ---------------------------------------------------------------------------
  useEffect(() => {
    if (!user) return;

    // Minta kebenaran notifikasi sebaik sahaja pengguna log masuk
    if ("Notification" in window && Notification.permission !== "granted") {
      Notification.requestPermission();
    }

    const checkLateArrival = async () => {
      try {
          const now = new Date();
          const day = now.getDay();

          // 1. Semak Hari Bekerja (0 = Ahad, 6 = Sabtu). Hanya jalankan Isnin (1) - Jumaat (5)
          if (day === 0 || day === 6) return;

          // 2. Dapatkan Tetapan Sistem
          const settings = await api.getSettings();

          // 3. Jika Mod Cuti Sekolah ON, hentikan proses (tiada notifikasi)
          if (settings.schoolHolidayMode) return;

          // 4. Semak jika notifikasi sudah dihantar hari ini untuk elak spam
          const todayStr = now.toISOString().split('T')[0];
          const storageKey = `notified_late_${user.email}_${todayStr}`;
          if (sessionStorage.getItem(storageKey)) return;

          // 5. Semak Rekod Kehadiran (Adakah sudah Clock In?)
          const history = await api.getHistory(user.email);
          const hasRecord = history.find(h => h.date === todayStr);

          // Jika sudah ada rekod (Hadir/Cuti/Luar), tidak perlu notifikasi
          if (hasRecord) return;

          // 6. Bandingkan Masa Semasa dengan Masa Masuk Rasmi
          const userRole = user.role || user.position || 'GURU';
          // Dapatkan masa masuk ikut jawatan, atau default GURU, atau default 07:30
          const targetTimeStr = settings.roleClockInTimes[userRole] || settings.roleClockInTimes['GURU'] || "07:30";

          const [tHour, tMin] = targetTimeStr.split(':').map(Number);
          const targetTime = new Date();
          targetTime.setHours(tHour, tMin, 0, 0);

          // Jika masa sekarang melebihi waktu masuk
          if (now > targetTime) {
            const message = "SILA CLOCK IN SEKARANG, ANDA TELAH LEWAT";

            // Hantar Notifikasi
            if ("Notification" in window && Notification.permission === "granted") {
              new Notification("Sistem Kehadiran Pintar", {
                body: message,
                icon: "https://i.ibb.co/FbdxdqGc/skpk.png",
                tag: "late-notification"
              });
            } else {
              // Fallback jika notifikasi diblock atau tidak disokong
              alert(message);
            }

            // Tandakan sudah dinotifikasi hari ini dalam Session Storage
            sessionStorage.setItem(storageKey, 'true');
          }
      } catch (err) {
          // Swallow errors to prevent "Uncaught" in console during background checks
          console.warn("Background check skipped (Offline/Error):", err);
      }
    };

    // Jalankan semakan setiap 1 minit (60000ms)
    const intervalId = setInterval(checkLateArrival, 60000);

    // Jalankan sekali sebaik sahaja component mount
    checkLateArrival();

    return () => clearInterval(intervalId);
  }, [user]); // Re-run effect if user changes

  const handleLogin = (userData: User) => {
    localStorage.setItem('userSession', JSON.stringify(userData));
    setUser(userData);
  };

  const handleUpdateUser = (updatedUser: User) => {
    localStorage.setItem('userSession', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const handleLogout = () => {
    localStorage.removeItem('userSession');
    setUser(null);
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
      <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-indigo-600 font-bold animate-pulse tracking-widest text-xs uppercase">Sila Tunggu...</p>
    </div>
  );

  const isAuthPage = location.pathname === '/auth';

  return (
