Sistem anda memerlukan satu penghubung (backend) untuk menyimpan data ke Google Sheets secara kekal. Berikut adalah kod **Google Apps Script** yang lengkap dan telah disesuaikan dengan fungsi-fungsi dalam `mockApi.ts` anda (seperti `REGISTER_STAFF`, `CLOCK_IN`, dll).

### Spesifikasi Skrip:
1.  **Dua Tab Automatik**: Skrip akan membina tab `Staf` dan `Kehadiran` secara automatik jika belum wujud.
2.  **CRUD Staf**: Menyokong pendaftaran, kemaskini, dan pemadaman staf.
3.  **Log Kehadiran**: Mencatat masa, lokasi (lat/long), status, dan pautan dokumen.
4.  **CORS Friendly**: Menggunakan output JSON yang serasi dengan panggilan `fetch` dari web app.

---

### Kod Google Apps Script (`Code.gs`)

Sila salin kod ini ke dalam Editor Google Apps Script anda:

```javascript
/**
 * SISTEM KEHADIRAN PINTAR SKPK - BACKEND ENGINE
 * Author: Roziman Bin Emran (Admin System)
 */

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheetStaf = getOrCreateSheet(ss, "Staf");
  var sheetKehadiran = getOrCreateSheet(ss, "Kehadiran");

  var data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  var action = data.action;

  // --- ACTION: REGISTER / UPDATE STAFF ---
  if (action === "REGISTER_STAFF" || action === "UPDATE_STAFF") {
    var email = data.email;
    var rows = sheetStaf.getDataRange().getValues();
    var foundIndex = -1;

    for (var i = 1; i < rows.length; i++) {
      if (rows[i][0] === email) {
        foundIndex = i + 1;
        break;
      }
    }

    var rowData = [
      data.email,
      data.name,
      data.position,
      data.jobGrade || "",
      data.phoneNumber || "",
      data.isAdmin || "NO",
      data.password || "123456",
      data.customClockIn || "",
      data.customClockOut || ""
    ];

    if (foundIndex > -1) {
      sheetStaf.getRange(foundIndex, 1, 1, rowData.length).setValues([rowData]);
    } else {
      sheetStaf.appendRow(rowData);
    }
    return res("Success: Staff updated");
  }

  // --- ACTION: DELETE STAFF ---
  if (action === "DELETE_STAFF") {
    var email = data.email;
    var rows = sheetStaf.getDataRange().getValues();
    for (var i = 1; i < rows.length; i++) {
      if (rows[i][0] === email) {
        sheetStaf.deleteRow(i + 1);
        return res("Success: Staff deleted");
      }
    }
    return res("Error: Staff not found");
  }

  // --- ACTION: CLOCK IN ---
  if (action === "CLOCK_IN") {
    // Format: Timestamp, Email, Name, Status, TimeIn, TimeOut, Reason, Lat, Lon, Document
    var timestamp = new Date();
    var rowKehadiran = [
      timestamp,
      data.email,
      data.name,
      data.status,
      data.timeIn,
      data.timeOut || "",
      data.reason || "",
      data.lat || "",
      data.lon || "",
      data.document || ""
    ];
    sheetKehadiran.appendRow(rowKehadiran);
    return res("Success: Attendance recorded");
  }

  return res("Error: Action not recognized");
}

// Helper: Ambil atau bina Sheet
function getOrCreateSheet(ss, name) {
  var sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    if (name === "Staf") {
      sheet.appendRow(["Email", "Name", "Position", "Grade", "Phone", "IsAdmin", "Password", "CustomIn", "CustomOut"]);
      sheet.getRange("1:1").setFontWeight("bold").setBackground("#f3f3f3");
    } else if (name === "Kehadiran") {
      sheet.appendRow(["Timestamp", "Email", "Name", "Status", "TimeIn", "TimeOut", "Reason", "Lat", "Lon", "Document"]);
      sheet.getRange("1:1").setFontWeight("bold").setBackground("#f3f3f3");
    }
  }
  return sheet;
}

// Helper: Response JSON
function res(msg) {
  return ContentService.createTextOutput(JSON.stringify({ result: msg }))
    .setMimeType(ContentService.MimeType.JSON);
}

// GET request (Opsional: Jika mahu debug melalui browser)
function doGet(e) {
  return ContentService.createTextOutput("SKPK Backend is Running. Use POST to send data.");
}
```

---

### Cara Guna & Deploy (Langkah demi Langkah):

1.  **Buka Google Sheet Baru**: Namakan ia "Data Kehadiran SKPK".
2.  **Buka Script Editor**: Pergi ke menu **Extensions** > **Apps Script**.
3.  **Tampal Kod**: Buang kod lama dan tampal kod di atas. Tekan ikon **Save** (namakan projek "Backend SKPK").
4.  **Deploy sebagai Web App**:
    *   Klik butang **Deploy** (kanan atas) > **New Deployment**.
    *   Select type: **Web App**.
    *   Description: "SKPK Version 1.0".
    *   Execute as: **Me** (Emel anda).
    *   Who has access: **Anyone** (Ini penting supaya app boleh hantar data tanpa login Google sekali lagi).
    *   Klik **Deploy**.
5.  **Authorize**: Berikan kebenaran (Permission) jika diminta. Jika keluar amaran "Google hasn't verified this app", klik **Advanced** > **Go to Backend SKPK (unsafe)**.
6.  **Salin URL**: Anda akan mendapat satu URL (bermula dengan `https://script.google.com/macros/s/...`).
7.  **Kemaskini `mockApi.ts`**:
    *   Cari pembolehubah `GOOGLE_SCRIPT_URL` dalam fail `services/mockApi.ts` anda.
    *   Tampal URL yang anda salin tadi di situ.

### Nota Tambahan:
*   Sistem anda sekarang akan secara automatik menghantar setiap rekod kehadiran (Clock-In) dan pendaftaran staf terus ke Google Sheet tersebut.
*   Untuk membolehkan `syncFromCloud` berfungsi, pastikan Google Sheet tersebut di-**Publish to Web** sebagai CSV (seperti yang anda sudah set dalam URL CSV sedia ada).

