import React, { useEffect, useState } from 'react';
import { StaffMember, AttendanceStatus, AttendanceRecord, User } from '../types';
import { api } from '../services/mockApi';
import { Search, Filter, Phone, MessageCircle, ArrowLeft, Calendar, FileText, ExternalLink, X, Clock, RefreshCw } from 'lucide-react';

export const Directory: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [staff, setStaff] = useState<StaffMember[]>([]);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState<string>('ALL');
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);

  // Drill-down State
  const [selectedStaff, setSelectedStaff] = useState<StaffMember | null>(null);
  const [staffHistory, setStaffHistory] = useState<AttendanceRecord[]>([]);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [historyLoading, setHistoryLoading] = useState(false);

  // Admin Check
  const isAdmin = currentUser.isAdmin === 'YES' || currentUser.email.toLowerCase().includes('admin');

  const loadStaffData = async (background = false) => {
      if (!background) setIsRefreshing(true);

      // Sync cloud data first
      await api.syncFromCloud();
      // Then get staff
      const data = await api.getStaff();
      setStaff(data);

      setLoading(false);
      if (!background) setIsRefreshing(false);
  };

  useEffect(() => {
    loadStaffData();

    // Auto-refresh every 15 seconds to update status
    const interval = setInterval(() => {
        loadStaffData(true);
    }, 15000);

    return () => clearInterval(interval);
  }, []);

  const handleStaffClick = async (person: StaffMember) => {
      // Access Control: Only admins can view details
      if (!isAdmin) return;

      setSelectedStaff(person);
      setHistoryLoading(true);
      const history = await api.getHistory(person.email);
      setStaffHistory(history);
      setHistoryLoading(false);
  };

  const filteredStaff = staff.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(search.toLowerCase()) || s.position.toLowerCase().includes(search.toLowerCase());
    const matchesFilter = filter === 'ALL' || s.status === filter;
    return matchesSearch && matchesFilter;
  });

  const filteredHistory = staffHistory.filter(h => {
      if (startDate && h.date < startDate) return false;
      if (endDate && h.date > endDate) return false;
      return true;
  });

  const getStatusColor = (status: AttendanceStatus) => {
    switch(status) {
        case AttendanceStatus.WORKING: return 'bg-green-100 text-black border-green-200';
        case AttendanceStatus.OUTSTATION: return 'bg-blue-100 text-black border-blue-200';
        case AttendanceStatus.LEAVE: return 'bg-red-100 text-black border-red-200';
        default: return 'bg-gray-100 text-gray-500 border-gray-200';
    }
  };

  const getWhatsAppLink = (phone: string | undefined) => {
      if (!phone) return '#';
      let clean = phone.replace(/\D/g, '');
      if (clean.startsWith('0')) {
          clean = '6' + clean;
      }
      return `https://wa.me/${clean}`;
  };

  const openDocument = (data: string) => {
      const win = window.open();
      if (win) {
          win.document.write(`<iframe src="${data}" frameborder="0" style="border:0; top:0px; left:0px; bottom:0px; right:0px; width:100%; height:100%;" allowfullscreen></iframe>`);
      }
  };

  if (selectedStaff) {
      return (
          <div className="min-h-screen px-4 py-8 max-w-lg mx-auto pb-32 bg-[#f8f9fc] animate-fade-in">
              <button 
                onClick={() => setSelectedStaff(null)}
                className="flex items-center gap-2 text-indigo-600 font-bold text-sm mb-6 hover:translate-x-1 transition-transform"
              >
                  <ArrowLeft size={18} /> Kembali ke Senarai Staf
              </button>

              <div className="bg-white p-6 rounded-[32px] shadow-sm mb-6 border border-gray-100 flex items-center gap-4">
                  <img src={selectedStaff.photo} className="w-16 h-16 rounded-2xl object-cover shadow-sm" alt={selectedStaff.name} />
                  <div>
                      <h3 className="font-bold text-gray-900 leading-tight">{selectedStaff.name}</h3>
                      <p className="text-xs text-gray-400 font-medium">{selectedStaff.position}</p>
                  </div>
              </div>

              {/* Filters for History */}
              <div className="bg-white p-5 rounded-[28px] shadow-sm mb-6 border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 pl-1">Tapis Mengikut Tarikh</p>
                  <div className="grid grid-cols-2 gap-3">
                      <div>
                          <label className="text-[9px] font-bold text-gray-300 uppercase mb-1 block pl-1">Mula</label>
                          <input 
                              type="date" 
                              value={startDate}
                              onChange={(e) => setStartDate(e.target.value)}
                              className="w-full bg-gray-50 p-3 rounded-xl text-xs font-bold text-slate-900 outline-none"
                          />
                      </div>
                      <div>
                          <label className="text-[9px] font-bold text-gray-300 uppercase mb-1 block pl-1">Tamat</label>
                          <input 
                              type="date" 
                              value={endDate}
                              onChange={(e) => setEndDate(e.target.value)}
                              className="w-full bg-gray-50 p-3 rounded-xl text-xs font-bold text-slate-900 outline-none"
                          />
                      </div>
                  </div>
              </div>

              {/* History List */}
              <div className="space-y-3">
                  <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest pl-1 mb-4">Log Kehadiran</h4>
                  {historyLoading ? (
                      <div className="text-center py-8 text-gray-300 animate-pulse">Memuatkan sejarah...</div>
                  ) : filteredHistory.length > 0 ? (
                      filteredHistory.map((item) => (
                          <div key={item.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-50 animate-slide-up">
                              <div className="flex justify-between items-start mb-3">
                                  <div>
                                      <p className="text-sm font-bold text-gray-900">{item.date}</p>
                                      <p className="text-[10px] text-gray-400 font-medium uppercase">{item.name}</p>
                                  </div>
                                  <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold border ${getStatusColor(item.status)}`}>
                                      {item.status}
                                  </span>
                              </div>

                              <div className="flex items-center justify-between mt-4 pt-4 border-t border-gray-50">
                                  <div className="flex items-center gap-1.5 text-gray-400">
                                      <Clock size={12} />
                                      {item.status === AttendanceStatus.WORKING ? (
                                        <span className="text-[10px] font-bold uppercase">{item.timeIn}</span>
                                      ) : (
                                        <span className="text-[10px] font-bold uppercase text-gray-300">--:--</span>
                                      )}
                                  </div>

                                  {item.document ? (
                                      <button 
                                        onClick={() => openDocument(item.document!)}
                                        className="flex items-center gap-1.5 text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl text-[10px] font-bold hover:bg-indigo-100 transition-colors"
                                      >
                                          <FileText size={14} /> Lihat Dokumen
                                      </button>
                                  ) : (
                                      <span className="text-[10px] text-gray-300 font-bold uppercase italic">Tiada Dokumen</span>
                                  )}
                              </div>
                          </div>
                      ))
                  ) : (
                      <div className="bg-white p-8 rounded-3xl text-center border border-dashed border-gray-200">
                          <p className="text-gray-400 text-xs font-medium">Tiada rekod dijumpai bagi tempoh ini.</p>
                      </div>
                  )}
              </div>
          </div>
      );
  }

  return (
    <div className="min-h-screen px-4 py-8 max-w-lg mx-auto pb-32">
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-800 tracking-tight">Senarai Staf</h2>
          <button onClick={() => loadStaffData()} className={`p-2 rounded-full text-slate-400 hover:bg-white transition-all ${isRefreshing ? 'animate-spin text-indigo-500' : ''}`}>
              <RefreshCw size={20} />
          </button>
      </div>

      <div className="relative mb-4">
        <Search className="absolute left-4 top-3.5 text-gray-400" size={20} />
        <input 
            type="text" 
            className="w-full pl-12 pr-4 py-3.5 rounded-[24px] bg-white text-gray-900 border border-gray-100 shadow-sm outline-none focus:ring-2 focus:ring-indigo-100 transition-all placeholder:text-gray-300"
            placeholder="Cari nama atau jawatan..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
         {['ALL', 'BEKERJA', 'URUSAN LUAR', 'CUTI'].map(f => (
             <button 
                key={f}
                onClick={() => setFilter(f)}
                className={`whitespace-nowrap px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all ${filter === f ? 'bg-[#0f172a] text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
             >
                {f === 'ALL' ? 'Semua' : f}
             </button>
         ))}
      </div>

      <div className="space-y-3">
        {loading ? (
            <div className="text-center py-12 text-gray-300 animate-pulse">Memuatkan maklumat staf...</div>
        ) : filteredStaff.length > 0 ? (
            filteredStaff.map((person, idx) => (
                <div 
                    key={idx} 
                    className={`bg-white p-4 rounded-[28px] shadow-sm border border-gray-50 flex items-center gap-4 transition-all ${isAdmin ? 'hover:shadow-md active:scale-95 cursor-pointer' : 'cursor-default'}`}
                    onClick={(e) => { 
                        if (isAdmin) {
                            handleStaffClick(person); 
                        }
                    }}
                >
                    <div className="relative">
                        <img 
                            src={person.photo} 
                            alt={person.name} 
                            className="w-14 h-14 rounded-2xl object-cover border-2 border-white shadow-sm transition-transform group-hover:scale-110 flex-shrink-0" 
                            onClick={(e) => { 
                                if (isAdmin) {
                                    e.stopPropagation(); 
                                    handleStaffClick(person); 
                                }
                            }}
                        />
                        {person.status === AttendanceStatus.WORKING && (
                            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-2 border-white rounded-full"></div>
                        )}
                    </div>

                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-gray-800 truncate leading-tight mb-0.5">{person.name}</h4>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wide mb-2">{person.position}</p>
                        <span className={`px-2 py-0.5 rounded-lg text-[9px] font-bold border uppercase ${getStatusColor(person.status)}`}>
                            {person.status}
                        </span>
                    </div>
                    <div className="flex flex-col gap-2">
                        <a 
                            href={person.phoneNumber ? `tel:${person.phoneNumber}` : '#'}
                            className={`p-2.5 rounded-xl transition-all ${person.phoneNumber ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100 active:scale-90 shadow-sm' : 'bg-gray-50 text-gray-200 cursor-not-allowed'}`}
                            onClick={(e) => {
                                e.stopPropagation();
                                if (!person.phoneNumber) e.preventDefault();
                            }}
                            title="Hubungi"
                        >
                             <Phone size={16} />
                        </a>

                        <a 
                            href={getWhatsAppLink(person.phoneNumber)}
                            target={person.phoneNumber ? "_blank" : undefined}
                            rel="noopener noreferrer"
                            className={`p-2.5 rounded-xl transition-all ${person.phoneNumber ? 'bg-green-50 text-green-600 hover:bg-green-100 active:scale-90 shadow-sm' : 'bg-gray-50 text-gray-200 cursor-not-allowed'}`}
                            onClick={(e) => {
                                e.stopPropagation();
                                if (!person.phoneNumber) e.preventDefault();
                            }}
                            title="WhatsApp"
                        >
                             <MessageCircle size={16} />
                        </a>
                    </div>
                </div>
            ))
        ) : (
            <div className="text-center py-12 bg-white rounded-[32px] border border-dashed border-gray-200">
                <p className="text-gray-300 text-xs font-medium">Tiada staf dijumpai.</p>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { User, SystemSettings, StaffMember, AttendanceRecord } from '../types';
import { api } from '../services/mockApi';
import { ShieldCheck, Plus, X, Search, Umbrella, Trash, Edit2, MapPin, Clock, AlertTriangle, Save, UserPlus, Camera, FileText, Calendar, Briefcase, UserMinus, Settings, Map, Bell, List, Trash2, RefreshCw } from 'lucide-react';

export const AdminDashboard: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'warga' | 'sistem'>('warga');
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [staffList, setStaffList] = useState<StaffMember[]>([]);
  const [searchWarga, setSearchWarga] = useState('');

  const POSITIONS = ['GURU BESAR', 'PENOLONG KANAN', 'GURU', 'AKP', 'GURU PELATIH'];

  // Add Staff State
  const [showAddModal, setShowAddModal] = useState(false);
  const [addForm, setAddForm] = useState<User>({
      name: '',
      email: '',
      position: 'GURU',
      photo: `https://ui-avatars.com/api/?name=New+Staff&background=random`,
      isAdmin: 'NO',
      password: '123456'
  });

  // Settings State for New Role
  const [newRoleName, setNewRoleName] = useState('');

  // UI States
  const [loading, setLoading] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [deleteModal, setDeleteModal] = useState<{ isOpen: boolean; data: StaffMember | null }>({ isOpen: false, data: null });
  const [deleteRoleModal, setDeleteRoleModal] = useState<{ isOpen: boolean; role: string | null }>({ isOpen: false, role: null });
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);

  // Individual Time Setting State
  const [individualTimeModal, setIndividualTimeModal] = useState<{ isOpen: boolean; staff: StaffMember | null }>({ isOpen: false, staff: null });
  const [timeForm, setTimeForm] = useState({ customClockIn: '', customClockOut: '' });

  useEffect(() => {
    loadData();

    // LIVE: Auto-refresh data every 20 seconds to see latest status
    const interval = setInterval(() => {
        loadData(true);
    }, 20000);

    return () => clearInterval(interval);
  }, []);

  const loadData = async (background = false) => {
    if (!background) setLoading(true);
    else setIsRefreshing(true);

    try {
        if (background) await api.syncFromCloud(); // Fetch latest from cloud in background
        const s = await api.getSettings();
        setSettings(s);
        const staff = await api.getStaff();
        setStaffList(staff);
    } catch(e) {
        console.error(e);
    } finally {
        if (!background) setLoading(false);
        else setIsRefreshing(false);
    }
  };

  const handleAddStaff = async (e: React.FormEvent) => {
      e.preventDefault();
      setLoading(true);
      try {
          const res = await api.register({ ...addForm, password: '123456' });
          if (res.success) {
              await loadData();
              setShowAddModal(false);
              setAddForm({
                name: '',
                email: '',
                position: 'GURU',
                photo: `https://ui-avatars.com/api/?name=New+Staff&background=random`,
                isAdmin: 'NO',
                password: '123456'
              });
              alert("Staf baharu berjaya didaftarkan! Kata laluan lalai: 123456");
          } else {
              alert(res.message || "Pendaftaran gagal.");
          }
      } catch (err) {
          alert("Ralat sistem.");
      } finally {
          setLoading(false);
      }
  };

  const handleConfirmDelete = async () => {
      if (!deleteModal.data) return;
      setLoading(true);
      try {
          const success = await api.deleteUser(deleteModal.data.email);
          if (success) {
              await loadData();
              setDeleteModal({ isOpen: false, data: null });
          } else {
              alert("Gagal memadam staf.");
          }
      } catch (err) {
          alert("Ralat berlaku semasa memadam.");
      } finally {
          setLoading(false);
      }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>, mode: 'ADD' | 'EDIT') => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              if (mode === 'ADD') {
                  setAddForm(prev => ({ ...prev, photo: reader.result as string }));
              } else if (editingStaff) {
                  setEditingStaff(prev => prev ? ({ ...prev, photo: reader.result as string }) : null);
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSaveStaff = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingStaff) return;
      setLoading(true);
      try {
          const success = await api.adminUpdateUser(editingStaff.email, {
              name: editingStaff.name,
              position: editingStaff.position,
              isAdmin: editingStaff.isAdmin,
              photo: editingStaff.photo
          });
          if (success) {
              await loadData();
              setEditingStaff(null);
              alert("Maklumat staf berjaya dikemaskini.");
          }
      } catch (err) {
          alert("Gagal mengemaskini maklumat staf.");
      } finally {
          setLoading(false);
      }
  };

  const openTimeModal = (staff: StaffMember) => {
      setTimeForm({
          customClockIn: staff.customClockIn || '',
          customClockOut: staff.customClockOut || ''
      });
      setIndividualTimeModal({ isOpen: true, staff });
  };

  const handleSaveIndividualTime = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!individualTimeModal.staff) return;
      setLoading(true);
      try {
          // If empty string, send undefined to remove the custom time
          const updates = {
              customClockIn: timeForm.customClockIn || undefined,
              customClockOut: timeForm.customClockOut || undefined
          };

          const success = await api.adminUpdateUser(individualTimeModal.staff.email, updates);

          if (success) {
              await loadData();
              setIndividualTimeModal({ isOpen: false, staff: null });
              alert("Waktu kerja individu berjaya dikemaskini.");
          }
      } catch (err) {
          alert("Gagal mengemaskini waktu kerja.");
      } finally {
          setLoading(false);
      }
  };

  const handleUpdateSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!settings) return;
    setLoading(true);
    try {
        const success = await api.updateSettings(settings);
        if (success) {
            alert("Tetapan sistem berjaya dikemaskini!");
        }
    } catch (err) {
        alert("Gagal mengemaskini tetapan.");
    } finally {
        setLoading(false);
    }
  };

  const handleAddRole = () => {
      if (!newRoleName.trim() || !settings) return;

      const role = newRoleName.trim().toUpperCase();

      if (settings.roleClockInTimes[role]) {
          alert("Jawatan ini sudah wujud.");
          return;
      }

      const updatedSettings = { ...settings };
      // Set default times
      updatedSettings.roleClockInTimes = { ...updatedSettings.roleClockInTimes, [role]: "07:30" };
      updatedSettings.roleClockOutTimes = { ...updatedSettings.roleClockOutTimes, [role]: "16:30" };

      setSettings(updatedSettings);
      setNewRoleName('');
  };

  const initiateDeleteRole = (role: string) => {
      setDeleteRoleModal({ isOpen: true, role });
  };

  const executeDeleteRole = () => {
      if (!settings || !deleteRoleModal.role) return;

      const roleToDelete = deleteRoleModal.role;
      const updatedSettings = { ...settings };
      const newIn = { ...updatedSettings.roleClockInTimes };
      const newOut = { ...updatedSettings.roleClockOutTimes };

      delete newIn[roleToDelete];
      delete newOut[roleToDelete];

      updatedSettings.roleClockInTimes = newIn;
      updatedSettings.roleClockOutTimes = newOut;
      setSettings(updatedSettings);
      setDeleteRoleModal({ isOpen: false, role: null });
  };

  const filteredStaff = staffList.filter(s => 
    s.name.toLowerCase().includes(searchWarga.toLowerCase()) || 
    s.email.toLowerCase().includes(searchWarga.toLowerCase())
  );

  return (
    <div className="min-h-screen px-4 py-8 max-w-lg mx-auto pb-32 bg-[#f8f9fc]">

      {/* HEADER CARD */}
      <div className="bg-white rounded-[32px] p-6 shadow-sm mb-6">
          <div className="flex justify-between items-start mb-6">
            <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600">
                    <ShieldCheck size={24} />
                </div>
                <div>
                    <h2 className="text-xl font-bold text-[#0f172a]">Panel Pentadbir</h2>
                    <p className="text-xs text-gray-400 font-medium">Pengurusan sistem dan staf sekolah</p>
                </div>
            </div>
            {isRefreshing && <RefreshCw size={16} className="text-indigo-400 animate-spin mt-2" />}
          </div>

          <div className="flex bg-[#f1f5f9] p-1.5 rounded-2xl">
              <button 
                onClick={() => setActiveTab('warga')}
                className={`flex-1 py-3 text-xs font-bold rounded-xl transition-all ${activeTab === 'warga' ? 'bg-[#0f172a] text-white shadow-md' : 'text-gray-400'}`}
              >
                  PENGURUSAN STAF
              </button>
              <button 
                onClick={() => setActiveTab('sistem')}
                className={`flex-1 py-3 text-xs font-bold rounded-xl transition-all ${activeTab === 'sistem' ? 'bg-[#0f172a] text-white shadow-md' : 'text-gray-400'}`}
              >
                  TETAPAN SISTEM
              </button>
          </div>
      </div>

      {activeTab === 'warga' && (
          <div className="animate-fade-in space-y-4">
              <div className="flex gap-3">
                  <div className="relative flex-1">
                      <Search className="absolute left-5 top-4 text-gray-400" size={20} />
                      <input 
                        type="text" 
                        placeholder="Cari staf..." 
                        value={searchWarga}
                        onChange={(e) => setSearchWarga(e.target.value)}
                        className="w-full bg-white pl-14 pr-5 py-4 rounded-3xl text-sm font-bold text-slate-900 shadow-sm outline-none focus:ring-2 focus:ring-indigo-100 placeholder:text-gray-400"
                      />
                  </div>
                  <button 
                    onClick={() => setShowAddModal(true)}
                    className="w-14 h-14 bg-indigo-600 text-white rounded-3xl flex items-center justify-center shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-90"
                  >
                      <UserPlus size={24} />
                  </button>
              </div>

              <div className="space-y-4">
                  {filteredStaff.map((staff, idx) => (
                      <div key={idx} className="bg-white rounded-[32px] p-6 shadow-sm flex flex-col items-center text-center relative border border-transparent hover:border-indigo-100 transition-all">
                          {/* Admin Indicator (Left) */}
                          <div className="absolute top-4 left-4">
                              {staff.isAdmin === 'YES' && <ShieldCheck size={18} className="text-indigo-600" />}
                          </div>

                          {/* Status Dot */}
                          <div className={`absolute top-4 left-1/2 -translate-x-1/2 w-2 h-2 rounded-full ${
                              staff.status === 'BEKERJA' ? 'bg-green-500' :
                              staff.status === 'CUTI' ? 'bg-pink-500' :
                              staff.status === 'URUSAN LUAR' ? 'bg-blue-500' : 'bg-slate-300'
                          }`}></div>

                          {/* Individual Time Setting Button (Top Right - Clock Icon) */}
                          <button
                                onClick={() => openTimeModal(staff)}
                                className={`absolute top-4 right-4 w-9 h-9 rounded-full flex items-center justify-center transition-all ${staff.customClockIn ? 'bg-indigo-600 text-white shadow-md' : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'}`}
                                title="Tetapkan Masa Individu"
                          >
                                <Clock size={16} />
                          </button>

                          <img src={staff.photo} className="w-20 h-20 rounded-2xl mb-3 object-cover shadow-md" alt={staff.name} />
                          <h3 className="font-bold text-gray-800 text-sm leading-tight">{staff.name.toUpperCase()}</h3>
                          <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">{staff.position}</span>

                          {/* Indicator if custom time is set */}
                          {staff.customClockIn && (
                              <span className="mt-2 text-[9px] font-bold text-white bg-indigo-500 px-2 py-0.5 rounded">
                                  Khas: {staff.customClockIn}
                              </span>
                          )}

                          <div className="flex w-full gap-2 mt-4">
                              <button onClick={() => setEditingStaff(staff)} className="flex-1 py-3 bg-[#f8fafc] text-slate-900 rounded-xl text-[10px] font-bold uppercase hover:bg-slate-100 transition-colors">Kemaskini</button>

                              {staff.email !== currentUser.email && (
                                <button 
                                    onClick={() => setDeleteModal({ isOpen: true, data: staff })}
                                    className="w-12 flex items-center justify-center bg-red-50 text-red-500 rounded-xl hover:bg-red-100 transition-colors"
                                >
                                    <Trash size={16} />
                                </button>
                              )}
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      {activeTab === 'sistem' && settings && (
          <div className="animate-fade-in space-y-6">
              <form onSubmit={handleUpdateSettings} className="space-y-6">

                  {/* LOKASI GEOFENCE (Warna Putih dengan Teks Gelap) */}
                  <div className="bg-white rounded-[32px] p-8 shadow-sm border border-slate-100 text-slate-900">
                      <h3 className="text-sm font-bold uppercase tracking-[0.2em] mb-6 flex items-center gap-3 text-indigo-600">
                          <Map size={20} /> Parameter Lokasi
                      </h3>
                      <div className="space-y-4">
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Latitud</label>
                                  <input 
                                      type="number" step="any"
                                      value={settings.targetLat}
                                      onChange={(e) => setSettings({...settings, targetLat: parseFloat(e.target.value)})}
                                      className="w-full bg-slate-50 border border-slate-100 px-4 py-3 rounded-xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-indigo-100 focus:bg-white transition-all"
                                  />
                              </div>
                              <div>
                                  <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Longitud</label>
                                  <input 
                                      type="number" step="any"
                                      value={settings.targetLon}
                                      onChange={(e) => setSettings({...settings, targetLon: parseFloat(e.target.value)})}
                                      className="w-full bg-slate-50 border border-slate-100 px-4 py-3 rounded-xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-indigo-100 focus:bg-white transition-all"
